```typescript
export class LLMService {
  private providers: Map<LLMProviderName, LLMProvider>;
  private primaryProvider: LLMProviderName;
  private fallbackOrder: LLMProviderName[];

  constructor() {
    // Charge LLM_PROVIDER depuis env, défaut 'anthropic'
    // Construit fallbackOrder : exclut le primary, inclut les providers configurés
    this.providers = new Map([
      ['anthropic', new AnthropicProvider()],
      ['openai', new OpenAIProvider()],
      ['openrouter', new OpenRouterProvider()]
    ]);
  }

  async generate(params): Promise<string> { /* avec fallback */ }
  async stream(params): Promise<void> { /* avec fallback */ }
  private async tryFallback(params, originalError, excludeProviders): Promise<...>
}
export const llmService = new LLMService();
```
Variables d'env requises dans `config/env.ts` : `LLM_PROVIDER`, `ANTHROPIC_API_KEY`, `OPENAI_API_KEY`, `OPENROUTER_API_KEY`. Retourner 503 avec header `Retry-After: 60` si tous les providers échouent.

